def is_palindrome(s):
    s = s.lower().replace(' ', '')
    return s == s[::-1]

def palindrome_check(string):
    left = 0
    right = len(string) - 1
    while left < right:
        if string[left] != string[right]:
            return False
        left += 1
        right -= 1
    return True

