            print(f"{num} is prime")

def gcd(a: int, b: int) -> int:
    """
    Calculate the Greatest Common Divisor (GCD) of two integers
    using the Euclidean algorithm.
    """
    while b != 0:
        a, b = b, a % b  # Replace a with b and b with a mod b
    return abs(a)

